#include<bits/stdc++.h>
using namespace std;
int main() {
	int n;
	cin >> n;
	int a[n][3];
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < 3; j++) {
			cin >> a[i][j];
		}
	}
	int b[n];
	for(int i=0;i<n;i++){
		b[i]=1;
	}
	for (int i = 0; i < n-1; i++) {
		for (int j = i; j < n; j++) {
			if (a[i][0] + a[i][1] + a[i][2] > a[j][0] + a[j][1] + a[j][2]) {
				b[j]++;
			} else if (a[i][0] + a[i][1] + a[i][2] < a[j][0] + a[j][1] + a[j][2])  {
				b[i]++;
			} else {
				if (a[i][0] + a[i][1]  >  a[j][0] + a[j][1] ) {
					b[j]++;
				} else if (a[i][0] + a[i][1]   <  a[j][0] + a[j][1] ) {
					b[i]++;
				} else {
					if (max(a[i][0], a[i][1]) > max(a[j][0], a[j][1])) {
						b[j]++;
					} else if (max(a[i][0], a[i][1]) < max(a[j][0], a[j][1])) {
						b[i]++;
					}
				}
			}
		}
	}

	for (int i = 0; i < n; i++) {
		cout << b[i] << endl;
	}
	return 0;
}
